/**
 * @param {number[]} nums
 * @param {number[][]} edges
 * @return {number}
 */
function solve(nums, edges) {
    const N = nums.length;

    // 1. Build Adjacency Matrix
    const adj = Array(N).fill(0).map(() => Array(N).fill(false));
    for (const [u, v] of edges) {
        adj[u][v] = true;
        adj[v][u] = true;
    }

    let finalCount = 0;

    // 2. Iterate through all non-empty subsets (masks M from 1 to 2^N - 1)
    const totalSubsets = 1 << N;
    for (let M = 1; M < totalSubsets; M++) {

        // --- Check Parity and Node Count ---
        let sum = 0;
        let nodeCount = 0;
        for (let i = 0; i < N; i++) {
            if ((M >> i) & 1) {
                sum += nums[i];
                nodeCount++;
            }
        }

        if (sum % 2 !== 0) {
            continue; // Parity check failed
        }

        // --- Check Connectivity ---

        if (nodeCount === 1) {
            // Single node subsets are always connected.
            finalCount++;
            continue;
        }

        // If nodeCount > 1, perform BFS

        // Find starting node s (the node with the lowest index in M)
        let startNode = -1;
        for (let i = 0; i < N; i++) {
            if ((M >> i) & 1) {
                startNode = i;
                break;
            }
        }

        // BFS setup
        let visitedMask = 0;
        let queue = [startNode];
        visitedMask |= (1 << startNode);
        let visitedCount = 1;

        let head = 0;
        while (head < queue.length) {
            let u = queue[head++];

            for (let v = 0; v < N; v++) {
                // Check conditions for transition u -> v:
                // 1. v must be in the subset M: ((M >> v) & 1)
                // 2. Edge (u, v) must exist: adj[u][v]
                // 3. v must not be visited yet: !((visitedMask >> v) & 1)
                if (((M >> v) & 1) && adj[u][v] && !((visitedMask >> v) & 1)) {
                    visitedMask |= (1 << v);
                    queue.push(v);
                    visitedCount++;
                }
            }
        }

        if (visitedCount === nodeCount) {
            // Connected AND sum is even
            finalCount++;
        }
    }

    return finalCount;
}

